head.script:
/**
 * 화 면 명 : 임대차[전대차] 경매현황
 * 메뉴경로 : 공통/총무업무/임대차관리/임대차[전대차] 계약관리/임대차[전대차] 계약기본정보
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/cm/bc/rentloan/zz_900_01_06b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-10-24
 * 수정이력  :
 *    - 2025-10-24      정승혜    최초작성
 *    - 2025-11-26      정승혜    준수사항 적용
 *    - 2025-12-23      정승혜    pub 경로 -> ui로 변경 / f_winOpen수정
 *    - 2025-12-24      정승혜    popTitleCh 적용
 *    - 2026-01-08      정승혜    기타수정
 *    - 2026-01-19      정승혜    submitdone 조건수정
 * 메모 :
 * 해당파일 명도소송현황 없음 -> f_winOpen에서 주석처리 / ChainedISNm없음 / f_RentloanShapeCdChange 없음
 * 
 * test를 위해 새로 만든 계약번호 
 * dma_ctrt(map) 으로 sbm_retrieve 받아서 
 * scwin.ctrt_length에 개수 저장후 바인딩하고
 * sbm_tr_save 할때 dma_ctrt(map) -> ds_ctrt_list(list) 담아서
 * scwin.ctrt_length 조건으로 modifyRowStatus 값 변경
 * 해야함 리스트 :
 */

//hidden
scwin.hid_rentloanNo = "";
scwin.hid_rentloanSeq = "";
scwin.hid_uppermostBizDomCd = "";

scwin.params = "";

scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_01_01b.xml";
scwin.strCtrtBaseSdId = "/ui/cm/bc/rentloan/zz_900_01_02b.xml";

scwin.rentloanNo = "";
scwin.rentloanSeq = "";
scwin.mode = "";
scwin.eqSelBizDom = "";
scwin.cfValue = "";
scwin.iCfVal = "";

scwin.sRentloanNo = "";
scwin.sRentloanSeq = "";
scwin.sMode = "";
scwin.user = "";

scwin.memJson = $c.data.getMemInfo();
scwin.regId = scwin.memJson.userId;
scwin.sysAdminYn = scwin.memJson.sysAdminYn;

//////////////////////////////
scwin.uppermostBizDomCd = ""; //최상위사업영역
scwin.selBizDom = scwin.eqSelBizDom;

scwin.popYn = "";

scwin.ctrt_length = 0;

  //-------------------------------------------------------------------------
  // 화면로딩시
  //-------------------------------------------------------------------------
scwin.onpageload = function() {
    // getCodeList
    const codeOptions = [
        { grpCd : "ZZ910", compID : "lc_rentloanClsCd" },
        { grpCd : "ZZ911", compID : "lc_rentloanShapeCd" },
    ];
    $c.data.setCommonCode(codeOptions);    

    scwin.params = $c.data.getParameter();
    if(scwin.params["rentloanNo"] == null){scwin.rentloanNo = "";}else{scwin.rentloanNo = scwin.params["rentloanNo"]} //계약번호
    if(scwin.params["rentloanSeq"] == null){scwin.rentloanSeq = "";}else{scwin.rentloanSeq = scwin.params["rentloanSeq"]} //계약순번
    if(scwin.params["mode"] == null){scwin.mode = "";}else{scwin.mode = scwin.params["mode"]} //NEW, CHG, REN, MOD, DEL, ''
    if(scwin.params["selBizDom"] == null){scwin.eqSelBizDom = "";}else{scwin.eqSelBizDom = scwin.params["selBizDom"]}
    if(scwin.params["cf"] == null){scwin.cfValue = "";}else{scwin.cfValue = scwin.params["cf"]}
    scwin.iCfVal = parseInt(scwin.cfValue);
    if(scwin.params["popYn"] == null){scwin.popYn = "";}else{scwin.popYn = scwin.params["popYn"]}
    scwin.sRentloanNo = scwin.params["rentloanNo"];
    scwin.sRentloanSeq = scwin.params["rentloanSeq"];
    scwin.sMode = scwin.params["sMode"];
    scwin.user = scwin.params["regId"]; 

    switch (scwin.iCfVal) {
        case 1 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_01_01b.xml"; break;
        case 2 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_04_01b.xml"; break;
        case 3 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_03_01b.xml"; break;
        case 4 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_03_02b.xml"; break;
        case 5 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_03_04b.xml"; break;
        case 8 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_08_01b.xml"; break;
        case 9 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_09_01b.xml"; break;
        default : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_01_01b.xml"; break;
    }



};

scwin.ondataload = function() {
    //로그인한 사번으로 최상위사업영역을 가져오는 데이타셋 실행
    scwin.f_uppermostBizdom();

    scwin.f_tr_chk();

    ed_rentloanNo.setValue(scwin.sRentloanNo + "-" + scwin.sRentloanSeq);

    scwin.f_Retrieve();

    if(scwin.popYn == 'Y')	// 팝업으로 넘어오는 항목인 경우 목록 버튼 비활성화
    {
        $c.gus.cfDisableObjects([btn_save, btn_list]);
    }
    scwin.hid_uppermostBizDomCd = scwin.uppermostBizDomCd;
}

scwin.popTitleCh = function() {
    $c.data.setPopupTitle("임대차[전대차] 경매현황");
};
    //-------------------------------------------------------------------------
    // function name : f_winOpen
    // function desc : 화면이동
    // function Parameter : strIndex : 버튼
    //-------------------------------------------------------------------------  
// 버튼6개 
scwin.f_winOpen = function (strIndex) {
    let strPath = "";
    let vRentloanShapeCd = lc_rentloanShapeCd.getValue();
    scwin.uppermostBizDomCd = scwin.hid_uppermostBizDomCd;
    let pgmId = $c.data.getParameter($p, "menuInfo").pgmId;
    let rentloan = scwin.sRentloanNo+scwin.sRentloanSeq;

    let data = {};
    data.mode = scwin.sMode;
    data.cf = scwin.cfValue;
    data.selBizDom = scwin.uppermostBizDomCd;
    data.rentloanNo = scwin.sRentloanNo;
    data.rentloanSeq = scwin.sRentloanSeq;

    let opt = {};
    opt.width = "2500";
    opt.height = "1300";
    opt.modal = true;
    opt.title = "title";
    opt.id = "popup";

    switch (strIndex)
        {
            case 0:
                if(scwin.popYn == 'Y'){

                    data.popYn = "Y";
                    opt.popupName = "계약기본정보";

                    let sURL = "/ui/cm/bc/rentloan/zz_900_01_02b.xml";
                    $c.win.openPopup(sURL, opt, data);
                }else{
                    strPath = "/ui/cm/bc/rentloan/zz_900_01_02b.xml";
                    $c.win.openMenu('계약기본정보', strPath,pgmId,data,{openAction : "exist" , menuCode : rentloan, menuCode2 : "new"});
                    let tabObj = $p.top().tac_layout;
                    tabObj.setLabelText(tabObj.getSelectedTabIndex(), "계약기본정보");
                }
            break;

            case 1:
                if(scwin.popYn == 'Y'){

                    data.popYn = "Y";
                    opt.popupName = "담보평가";

                    let sURL = "/ui/cm/bc/rentloan/zz_900_01_03b.xml";
                    $c.win.openPopup(sURL, opt, data);
                }else{
                    strPath = "/ui/cm/bc/rentloan/zz_900_01_03b.xml";
                    $c.win.openMenu('담보평가', strPath,pgmId,data,{openAction : "exist" , menuCode : rentloan, menuCode2 : "new"});
                    let tabObj = $p.top().tac_layout;
                    tabObj.setLabelText(tabObj.getSelectedTabIndex(), "담보평가");
                }
            break;

            case 2:
                if(scwin.popYn == 'Y'){

                    data.popYn = "Y";
                    opt.popupName = "계약조건";

                    let sURL = "/ui/cm/bc/rentloan/zz_900_01_04b.xml";
                    $c.win.openPopup(sURL, opt, data);
                }else{
                    strPath = "/ui/cm/bc/rentloan/zz_900_01_04b.xml";
                    $c.win.openMenu('계약조건', strPath,pgmId,data,{openAction : "exist" , menuCode : rentloan, menuCode2 : "new"});
                    let tabObj = $p.top().tac_layout;
                    tabObj.setLabelText(tabObj.getSelectedTabIndex(), "계약조건");
                }
            break;

            case 3:
                if(scwin.popYn == 'Y'){
                    data.popYn = "Y";
                    opt.popupName = "검토의견 및 참고사항";

                    let sURL = "/ui/cm/bc/rentloan/zz_900_01_05b.xml";
                    $c.win.openPopup(sURL, opt, data);
                }else{
                    strPath = "/ui/cm/bc/rentloan/zz_900_01_05b.xml";
                    $c.win.openMenu('검토의견 및 참고사항', strPath,pgmId,data,{openAction : "exist" , menuCode : rentloan, menuCode2 : "new"});
                    let tabObj = $p.top().tac_layout;
                    tabObj.setLabelText(tabObj.getSelectedTabIndex(), "검토의견 및 참고사항");
                }
            break;

            case 4:
                // 해당파일 명도소송현황 없음
                /* if(vRentloanShapeCd == "01" || vRentloanShapeCd == "02"){ */
                    if(scwin.popYn == 'Y'){
                        data.popYn = "Y";
                        opt.popupName = "경매현황";

                        let sURL = "/ui/cm/bc/rentloan/zz_900_01_06b.xml";
                        $c.win.openPopup(sURL, opt, data);
                    }else{
                        strPath = "/ui/cm/bc/rentloan/zz_900_01_06b.xml";
                        $c.win.openMenu('경매현황', strPath,pgmId,data,{openAction : "exist" , menuCode : rentloan, menuCode2 : "new"});
                        let tabObj = $p.top().tac_layout;
                    tabObj.setLabelText(tabObj.getSelectedTabIndex(), "경매현황");
                    }
                    break;
                /* }else if(vRentloanShapeCd == "03" || vRentloanShapeCd == "04") {
                    if(scwin.popYn == 'Y'){
                        data.popYn = "Y";
                        opt.popupName = "명도소송현황";

                        let sURL = "/ui/cm/bc/rentloan/zz_900_02_06b.xml";
                        $c.win.openPopup(sURL, opt, data);
                    }else{
                        strPath = "/ui/cm/bc/rentloan/zz_900_02_06b.xml";
                        $c.win.openMenu('명도소송현황', strPath,strPath.substring(strPath.lastIndexOf("/") + 1).replace(/.xml/g,""),data);
                    }
                    break;
                }else{

                } */
            case 5:
                if(scwin.popYn == 'Y'){
                    data.popYn = "Y";
                    data.fileClsCd = "04";
                    opt.popupName = "첨부파일";

                    let sURL = "/ui/cm/bc/rentloan/zz_900_01_07b.xml";
                    $c.win.openPopup(sURL, opt, data);
                }else{
                    data.fileClsCd = "04";
                    strPath = "/ui/cm/bc/rentloan/zz_900_01_07b.xml";
                    $c.win.openMenu('첨부파일', strPath,pgmId,data,{openAction : "exist" , menuCode : rentloan, menuCode2 : "new"});
                    let tabObj = $p.top().tac_layout;
                    tabObj.setLabelText(tabObj.getSelectedTabIndex(), "첨부파일");

                }
            break;
    default :
    break;
        }
};

  //-------------------------------------------------------------------------
  // 조회 : 데이터를 조회한다.
  //-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    dma_search.set("rentloanNo", scwin.sRentloanNo);
    dma_search.set("rentloanSeq", scwin.sRentloanSeq);
    let condition = "";
    condition = "?rentloanNo=" + scwin.sRentloanNo + "&cf=" + scwin.cfValue + "&rentloanSeq=" + scwin.sRentloanSeq;
    sbm_retrieve.action = "/cm.bc.rentloan.RetrieveAuctionPrscondCMD.do" + condition;
    $c.sbm.execute(sbm_retrieve);
};

  //-------------------------------------------------------------------------
  // 저장 : 
  //-------------------------------------------------------------------------
scwin.f_Save = async function() {
    const cols = [];
    for (let i = 0; i < dma_ctrt.getCount(); i++) {
        cols.push(dma_ctrt.getKey(i));
    }

    cols.forEach(col => {
    ds_ctrt_list.setCellData(0, col, dma_ctrt.get(col));
    });

    if(ds_ctrt_list.getModifiedIndex().length != 0){
        ds_ctrt_list.modifyRowStatus(0, "U");
    }else{
        await $c.win.alert("변경된 내용이 없습니다.");
        return;
    }

    if (await $c.win.confirm(MSG_CM_CRM_001) ){
        $c.sbm.execute(sbm_tr_save);
    }
}

scwin.f_Ctrt = function() {
    //호출되는곳 없음
};

scwin.cfTabMenuAdd = function() {
    let sURL = scwin.strBasSdId;
    $c.win.openMenu('계약관리', sURL,sURL.substring(sURL.lastIndexOf("/") + 1).replace(/.xml/g,""));
};

scwin.f_tr_chk = function() {
    dma_search.set("rentloanNo", scwin.sRentloanNo);
    dma_search.set("rentloanSeq", scwin.sRentloanSeq);
    sbm_tr_chk.action = "/cm.bc.rentloan.RetrieveRentLoanContractBasisInformationCMD.do?rentloanNo=" + scwin.sRentloanNo + "&rentloanSeq=" + scwin.sRentloanSeq; 
    $c.sbm.execute(sbm_tr_chk);
};

scwin.f_rentloan_keyup = function(e) {
    let input = e.target;
    let val = input.value;

    // 1️ 아무것도 없으면 종료
    if (!val) return;

    // 2️ 첫 글자는 영문만 허용, 소문자면 대문자로 자동변환
    let first = val.charAt(0).toUpperCase();
    if (!/[A-Z]/.test(first)) {
        // 첫 글자가 영문이 아니면 제거
        first = '';
    }

    // 3️ 나머지 글자는 숫자만 남김
    let rest = val.substring(1).replace(/[^0-9]/g, '');

    // 4️ 12자리 넘으면 '-' 추가
    if (rest.length > 11) {
        rest = rest.substring(0, 11) + '-' + rest.substring(11, 15);
    }

    // 5️ 전체 조합 및 길이 제한
    let formatted = (first + rest).substring(0, 16);

    // 6️ 결과 반영
    input.value = formatted;

};

scwin.f_rentloan_click = function(e){
    let input = e.target;
    let val = input.value;

    // 1️ 아무것도 없으면 종료
    if (!val) return;

    // 2️ 첫 글자는 영문만 허용, 소문자면 대문자로 자동변환
    let first = val.charAt(0).toUpperCase();
    if (!/[A-Z]/.test(first)) {
        // 첫 글자가 영문이 아니면 제거
        first = '';
    }

    // 3️ 나머지 글자는 숫자만 남김
    let rest = val.substring(1).replace(/[^0-9]/g, '');

    // 4️ 12자리 넘으면 '-' 추가
    if (rest.length > 11) {
        rest = rest.substring(0, 11) + '-' + rest.substring(11, 15);
    }

    // 5️ 전체 조합 및 길이 제한
    let formatted = (first + rest).substring(0, 16);

    // 6️ 결과 반영
    input.value = formatted;
}

scwin.f_displayFm = function(e) {
    let val = e;

    let first = val.charAt(0).toUpperCase();
    if (!/[A-Z]/.test(first)) {
        // 첫 글자가 영문이 아니면 제거
        first = '';
    }
    let rest = val.substring(1).replace(/[^0-9]/g, '');
    if (rest.length > 11) {
            rest = rest.substring(0, 11) + '-' + rest.substring(11, 15);
        }
    let formatted = (first + rest).substring(0, 16);

    return formatted;
};

scwin.f_uppermostBizdom = function() {
    const params = {
        sysCd: "CommonEBC",
        queryId: "retrieveUppermostBizDomInfo",
        param1: scwin.memJson.empNo
    };
    dma_uppermostBizdom_param.setJSON(params);
    $c.sbm.execute(sbm_ds_uppermostBizdom);

};

scwin.sbm_ds_uppermostBizdom_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    if(ds_uppermostBizdom.getCellData(0, "col1") != "" && ds_uppermostBizdom.getCellData(0, "col1") != null ){
        if(scwin.selBizDom == "" || scwin.selBizDom == null){
            scwin.uppermostBizDomCd = ds_uppermostBizdom.getCellData(0, "col1");
        }else{
            scwin.uppermostBizDomCd = scwin.selBizDom;
        }        
    }else{
        scwin.uppermostBizDomCd = "252";
    }
};

// 서브미션
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    dma_ctrt.setJSON(e.responseJSON.GAUCE[0]);
    scwin.ctrt_length = e.responseJSON.GAUCE.length;

    if(ds_ctrt_list.getRowCount() == 0 ){
        ds_ctrt_list.clearSort();
        ds_ctrt_list.insertRow();
    }

    const cols = [];
    for (let i = 0; i < dma_ctrt.getCount(); i++) {
        cols.push(dma_ctrt.getKey(i));
    }

    cols.forEach(col => {
    ds_ctrt_list.setCellData(0, col, dma_ctrt.get(col));
    });

    dma_ctrt.set("rentloanNo", scwin.sRentloanNo);
    dma_ctrt.set("rentloanSeq", scwin.sRentloanSeq);

    if(scwin.ctrt_length != 0){
        ds_ctrt_list.modifyRowStatus(0, "R");
    }

};

// 서브미션
scwin.sbm_tr_chk_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    ds_out.setRowPosition(0);

    if (ds_out.getCellData(0, "dcsnYn") == "1") {	// 확정
        $c.gus.cfEnableObjects([]);
        $c.gus.cfDisableObjects([oRecevInfo, pu_auction]);
    } else {	// 미확정
        $c.gus.cfEnableObjects([oRecevInfo, oRecevInfo1, txt_etcAucPrscondCont, btn_save]);
        $c.gus.cfDisableObjects([oRecevInfo, pu_auction]);
    }
};

// 서브미션
scwin.sbm_tr_save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.ondataload();
};
